// ── Runtime ──────────────────────────────────────────────────────────────────

let adminLang = (() => {
  const saved = localStorage.getItem('ttzop_admin_lang');
  if (saved && ADMIN_UI[saved]) return saved;
  const browser = navigator.language.split('-')[0];
  if (ADMIN_UI[browser]) return browser;
  return 'en';
})();

let _onLangChange = null;

function t(key) {
  return ADMIN_UI[adminLang]?.[key] ?? ADMIN_UI['en']?.[key] ?? key;
}

function setAdminLang(lang) {
  if (!ADMIN_UI[lang]) return;
  adminLang = lang;
  localStorage.setItem('ttzop_admin_lang', lang);
  const langDef = ADMIN_LANGS.find(l => l.code === lang);
  document.documentElement.lang = lang;
  document.documentElement.dir = langDef?.dir || 'ltr';
  applyUILang();
  if (_onLangChange) _onLangChange(lang);
}

function applyUILang() {
  document.querySelectorAll('[data-i18n]').forEach(el => {
    el.textContent = t(el.dataset.i18n);
  });
  document.querySelectorAll('[data-i18n-placeholder]').forEach(el => {
    el.placeholder = t(el.dataset.i18nPlaceholder);
  });
  // Update dropdown state (topbar + login screen)
  const curDef = ADMIN_LANGS.find(l => l.code === adminLang);
  const btnLabel = `${curDef?.label || adminLang.toUpperCase()} <span class="dd-arrow">▾</span>`;
  const btn = document.querySelector('#admin-lang-picker .admin-lang-dd-btn');
  if (btn) btn.innerHTML = btnLabel;
  const loginBtn = document.querySelector('#login-lang-picker .admin-lang-dd-btn');
  if (loginBtn) loginBtn.innerHTML = btnLabel;
  document.querySelectorAll('.admin-lang-dd-item').forEach(el => {
    el.classList.toggle('active', el.dataset.lang === adminLang);
  });
  if (typeof _updateTopbarSection === 'function') _updateTopbarSection(); // актыўны РМ у тапбары
  // Тултып назвы РМ на іконках панэлі (шырокі экран — толькі-іконкі) на мове інтэрфейсу
  document.querySelectorAll('.nav-item').forEach(item => {
    const lbl = item.querySelector('span:last-child');
    if (lbl) item.title = lbl.textContent.trim();
  });
}

function renderAdminLangPicker() {
  const container = document.getElementById('admin-lang-picker');
  if (!container) return;

  const knownCodes = new Set(ADMIN_LANGS.map(l => l.code));
  const customLangs = (typeof settings !== 'undefined' ? settings.languages || [] : [])
    .filter(l => !knownCodes.has(l.code));

  // Button shows current content lang (may be custom), not UI lang
  const activeLang = typeof currentSettingsLang !== 'undefined' ? currentSettingsLang : adminLang;
  const customActive = customLangs.find(l => l.code === activeLang);
  const btnLabel = customActive
    ? (customActive.label || customActive.code.toUpperCase())
    : (ADMIN_LANGS.find(l => l.code === adminLang)?.label || adminLang.toUpperCase());

  const knownItems = ADMIN_LANGS.map(l =>
    `<button class="admin-lang-dd-item${l.code === adminLang && !customActive ? ' active' : ''}" data-lang="${l.code}" onclick="setAdminLang('${l.code}');toggleAdminLangDropdown()">
      <span class="admin-lang-dd-code">${l.label}</span>
      <span class="admin-lang-dd-name">${l.name}</span>
    </button>`
  ).join('');

  const customSection = customLangs.length === 0 ? '' :
    `<div class="admin-lang-dd-sep"></div>` +
    customLangs.map(l =>
      `<button class="admin-lang-dd-item${l.code === activeLang ? ' active' : ''}" data-lang="${l.code}" onclick="selectCustomContentLang('${l.code}','${l.uiLang||'en'}');toggleAdminLangDropdown()">
        <span class="admin-lang-dd-code">${l.label || l.code.toUpperCase()}</span>
        <span class="admin-lang-dd-name">${l.name || l.label || l.code}</span>
      </button>`
    ).join('');

  container.innerHTML = `
    <button class="admin-lang-dd-btn" onclick="toggleAdminLangDropdown(event)">${btnLabel} <span class="dd-arrow">▾</span></button>
    <div class="admin-lang-dd-menu">${knownItems}${customSection}</div>`;
}

function toggleAdminLangDropdown(e) {
  if (e) {
    e.stopPropagation();
    document.querySelector('#admin-lang-picker .admin-lang-dd-menu')?.classList.toggle('open');
  } else {
    document.querySelector('#admin-lang-picker .admin-lang-dd-menu')?.classList.remove('open');
  }
}

function renderLoginLangPicker() {
  const container = document.getElementById('login-lang-picker');
  if (!container) return;
  const curDef = ADMIN_LANGS.find(l => l.code === adminLang);
  const items = ADMIN_LANGS.map(l =>
    `<button class="admin-lang-dd-item${l.code === adminLang ? ' active' : ''}" data-lang="${l.code}" onclick="setAdminLang('${l.code}');toggleLoginLangDropdown()">
      <span class="admin-lang-dd-code">${l.label}</span>
      <span class="admin-lang-dd-name">${l.name}</span>
    </button>`
  ).join('');
  container.innerHTML = `
    <button class="admin-lang-dd-btn" onclick="toggleLoginLangDropdown(event)">${curDef?.label || adminLang.toUpperCase()} <span class="dd-arrow">▾</span></button>
    <div class="admin-lang-dd-menu" style="right:0;left:auto">${items}</div>`;
}

function toggleLoginLangDropdown(e) {
  if (e) e.stopPropagation();
  document.querySelector('#login-lang-picker .admin-lang-dd-menu')?.classList.toggle('open');
}

document.addEventListener('click', e => {
  if (!e.target.closest('#admin-lang-picker')) {
    document.querySelector('#admin-lang-picker .admin-lang-dd-menu')?.classList.remove('open');
  }
  if (!e.target.closest('#login-lang-picker')) {
    document.querySelector('#login-lang-picker .admin-lang-dd-menu')?.classList.remove('open');
  }
});
